UPDATE t_p28211681_photo_secure_web.legal_documents
SET content = REPLACE(
    content,
    '<p>5.6. Изменение цен и Тарифов не применяется к уже оплаченным периодам и не ухудшает условия оплаченного доступа.</p>',
    '<p>5.6. Изменение цен и Тарифов не применяется к уже оплаченным периодам и не ухудшает условия оплаченного доступа.</p>'
    || '<p>5.7. Действующие Тарифы Сервиса (стоимость указана в рублях РФ за один месяц, НДС не применяется — НПД):</p>'
    || '<ul>'
    || '<li><b>Старт</b> — 0 ₽/мес (бесплатно): 1 ГБ хранилища, до 2 клиентов. Базовый функционал для начинающих.</li>'
    || '<li><b>Базовый</b> — 990 ₽/мес: 20 ГБ хранилища, до 50 клиентов, статистика и аналитика, отслеживание доходов.</li>'
    || '<li><b>Профи</b> — 2 500 ₽/мес: 100 ГБ хранилища, до 200 клиентов, статистика и аналитика, аналитика бронирований, отслеживание доходов, история загрузок.</li>'
    || '<li><b>Бизнес</b> — 5 000 ₽/мес: 200 ГБ хранилища, до 1000 клиентов, полная статистика и аналитика, аналитика бронирований, отслеживание доходов, история загрузок, статистика скачиваний.</li>'
    || '</ul>'
    || '<p>Состав и стоимость Тарифов могут обновляться; актуальная информация всегда размещена на Сайте в разделе «Тарифы». Изменения не ухудшают условия уже оплаченного периода (п. 5.6).</p>'
    || '<p>5.8. Внутренняя валюта «Энергия». В Сервисе используется внутренняя единица «Энергия», предназначенная для оплаты отдельных ресурсоёмких функций (в частности, инструментов обработки и ретуши фотографий). Энергия не является денежным средством, электронным средством платежа или криптовалютой, не подлежит обмену на денежные средства и возврату в денежной форме.</p>'
    || '<p>5.9. Пополнение Энергии осуществляется на Сайте по курсу 1 единица Энергии = 25 ₽. Минимальная сумма пополнения — 25 ₽. Доступны пакеты пополнения, например: 500 ₽ — 20 ед., 1 000 ₽ — 40 ед., 2 500 ₽ — 100 ед., 5 000 ₽ — 200 ед. Энергия зачисляется на баланс Заказчика в Личном кабинете после поступления оплаты; по факту пополнения формируется чек НПД.</p>'
    || '<p>5.10. Энергия расходуется по мере использования соответствующих функций согласно действующим тарифам списания, указанным на Сайте/в ЛК. Неизрасходованный остаток Энергии сохраняется на балансе Заказчика в течение срока действия аккаунта. Курс пополнения и стоимость функций в Энергии могут изменяться с публикацией на Сайте, без ухудшения условий уже приобретённого остатка.</p>'
)
WHERE slug = 'offer';